mapper.select:
SELECT
    statistics_data_table.push_operator,
    statistics_data_table.num_key,
    statistics_data_table.num_value,
    statistics_data_table.num_count,
    statistics_data_table.push_time
FROM
    statistics_data_table
WHERE
    statistics_data_table.push_operator = #{operator}
  AND statistics_data_table.num_key = #{num_key}
  AND statistics_data_table.num_value = #{num_value}
  AND DATE(statistics_data_table.push_time)=DATE(#{push_time});

mapper.update:
UPDATE statistics_data_table
SET statistics_data_table.num_count = #{num_count}
WHERE
    statistics_data_table.push_operator = #{operator}
  AND statistics_data_table.num_key=#{num_key}
  AND statistics_data_table.num_value=#{num_value}
  AND DATE(statistics_data_table.push_time)=DATE(#{push_time});
